  1	import React, { FC, useState } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import {
  7	  ActionList,
  8	  ActionListItem,
  9	  Alert,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  Text,
 14	  Title,
 15	} from '@patternfly/react-core';
 16	import { CloseIcon, WarningTriangleIcon } from '@patternfly/react-icons';
 17	import { rollbackStorageMigration } from '@virtualmachines/actions/actions';
 18	
 19	type VirtualMachineMigrationRollbackProps = {
 20	  onClose: () => void;
 21	  onContinue: () => void;
 22	  vm: V1VirtualMachine;
 23	};
 24	
 25	const VirtualMachineMigrationRollback: FC<VirtualMachineMigrationRollbackProps> = ({
 26	  onClose,
 27	  onContinue,
 28	  vm,
 29	}) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const [loadingRollback, setLoadingRollback] = useState(false);
 32	  const [errorRollback, setErrorRollback] = useState<Error>();
 33	
 34	  const rollback = async () => {
 35	    setLoadingRollback(true);
 36	
 37	    try {
 38	      await rollbackStorageMigration(vm);
 39	      onClose();
 40	    } catch (apiError) {
 41	      setErrorRollback(errorRollback);
 42	    } finally {
 43	      setLoadingRollback(false);
 44	    }
 45	  };
 46	
 47	  return (
 48	    <div className="pf-v6-c-wizard migration-status">
 49	      <div className="pf-v6-c-wizard__header">
 50	        <div className="pf-v6-c-wizard__close">
 51	          <Button aria-label={t('Close')} onClick={onClose} variant={ButtonVariant.plain}>
 52	            <CloseIcon />
 53	          </Button>
 54	        </div>
 55	        <div className="pf-v6-c-wizard__title">
 56	          <h2 className="pf-v6-c-wizard__title-text">{t('Migrate VirtualMachine storage')}</h2>
 57	        </div>
 58	        <div className="pf-v6-c-wizard__description">
 59	          {t('Migrate VirtualMachine storage to a different StorageClass.')}
 60	        </div>
 61	      </div>
 62	
 63	      <div className="migration-status__body">
 64	        <Title headingLevel="h2">
 65	          <WarningTriangleIcon color="var(--pf-t--global--color--status--warning--default)" />{' '}
 66	          {t('Stop migration')}
 67	        </Title>
 68	
 69	        <Text>{t('Are you sure you want to stop the VirtualMachine workloads?')}</Text>
 70	        <Text>
 71	          {t(
 72	            'Stopping the migration will cancel any remaining migrations that are scheduled or currently in progress',
 73	          )}
 74	        </Text>
 75	
 76	        <Text>
 77	          <Trans t={t}>
 78	            Select <strong>Rollback</strong> to return any completed migration to the original
 79	            StorageClass.
 80	          </Trans>
 81	        </Text>
 82	
 83	        {errorRollback && (
 84	          <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
 85	            {errorRollback?.message}
 86	          </Alert>
 87	        )}
 88	      </div>
 89	      <ActionList>
 90	        <ActionListItem>
 91	          <Button isLoading={loadingRollback} onClick={rollback}>
 92	            {t('Rollback')}
 93	          </Button>
 94	        </ActionListItem>
 95	        <ActionListItem>
 96	          <Button onClick={onContinue} variant={ButtonVariant.link}>
 97	            {t('Continue')}
 98	          </Button>
 99	        </ActionListItem>
100	      </ActionList>
101	    </div>
102	  );
103	};
104	
105	export default VirtualMachineMigrationRollback;

